import redis.clients.jedis.Jedis;

public class redisTokenVerify {
    public void verify(String token) {
        Jedis jedis = new Jedis("localhost");
        String value = jedis.get(token);
        if (value != null) {
            //删除token
            jedis.del(token);
            //校验成功
        } else {
            //校验失败
        }
